import React, { useState, useEffect, createContext, useContext } from "react";

const OrderContext = createContext();

export const OrderProvider = ({ children }) => {
  // Initialize the order state by reading from localStorage (only once on component mount)
  const [order, setOrder] = useState(() => {
    const savedOrder = localStorage.getItem('order');
    return savedOrder ? JSON.parse(savedOrder) : {}; // Use saved order if it exists
  });

  const [menu, setMenu] = useState([]);

  // Update localStorage whenever `order` changes
  useEffect(() => {
    if (Object.keys(order).length > 0) {
      localStorage.setItem('order', JSON.stringify(order)); // Update order in localStorage
    }
  }, [order]); // Only update when the order changes

  const addToOrder = (ProductId) => {
    setOrder((prev) => ({
      ...prev,
      [ProductId]: (prev[ProductId] || 0) + 1,
    }));
  };

  const removeItem = (ProductId) => {
    setOrder((prev) => {
      const temp = { ...prev };
      delete temp[ProductId];
      return temp;
    });
  };

  const removeFromOrder = (ProductId) => {
    setOrder((prev) => ({
      ...prev,
      [ProductId]: Math.max((prev[ProductId] || 1) - 1, 0), // Ensure we don't go below 0
    }));
  };

  return (
    <OrderContext.Provider value={{ order, addToOrder, menu, setMenu, removeFromOrder, removeItem ,setOrder }}>
      {children}
    </OrderContext.Provider>
  );
};

export const useOrderContext = () => useContext(OrderContext);
